// Read docx file using docx library
const fs = require('fs');
const path = require('path');

// Try to read as binary and extract text
async function readDocx() {
  try {
    const docx = await import('docx');
    // Actually, let's use a simpler approach - read the zip structure
    const data = fs.readFileSync('IPK.docx');
    console.log('File size:', data.length);
    console.log('First bytes:', data.slice(0, 20).toString('hex'));
  } catch (e) {
    console.log('Error with docx import:', e.message);
  }

  // Try using adm-zip
  try {
    const AdmZip = await import('adm-zip');
    const zip = new AdmZip.default('IPK.docx');
    const entries = zip.getEntries();
    console.log('Zip entries:', entries.map(e => e.entryName));

    // Read document.xml
    const docXml = zip.readAsText('word/document.xml');
    console.log('Document XML length:', docXml.length);
    console.log('Document XML preview (first 5000 chars):', docXml.substring(0, 5000));
  } catch (e) {
    console.log('Error with adm-zip:', e.message);
  }
}

readDocx();

