     1→import { Injectable, NotFoundException, ConflictException } from '@nestjs/common';
     2→import { BuildingRepository } from './building.repository';
     3→import { CreateBuildingDto } from './dto/create-building.dto';
     4→import { UpdateBuildingDto } from './dto/update-building.dto';
     5→import { BuildingResponseDto } from './dto/building-response.dto';
     6→
     7→@Injectable()
     8→export class BuildingService {
     9→  constructor(private readonly buildingRepository: BuildingRepository) {}
    10→
    11→  async create(data: CreateBuildingDto): Promise<BuildingResponseDto> {
    12→    // Проверка уникальности кадастрового номера
    13→    const existing = await this.buildingRepository.findByCadastralNumber(data.cadastralNumber);
    14→    if (existing) {
    15→      throw new ConflictException('Здание с таким кадастровым номером уже существует');
    16→    }
    17→    const building = await this.buildingRepository.create(data);
    18→    return this.toResponseDto(building);
    19→  }
    20→
    21→  async findAll(): Promise<BuildingResponseDto[]> {
    22→    const buildings = await this.buildingRepository.findAll();
    23→    return buildings.map(b => this.toResponseDto(b));
    24→  }
    25→
    26→  async findOne(id: string): Promise<BuildingResponseDto> {
    27→    const building = await this.buildingRepository.findById(id);
    28→    if (!building) {
    29→      throw new NotFoundException('Здание не найдено');
    30→    }
    31→    return this.toResponseDto(building);
    32→  }
    33→
    34→  async update(id: string, data: UpdateBuildingDto): Promise<BuildingResponseDto> {
    35→    // Проверяем, существует ли здание
    36→    await this.findOne(id); // выбросит NotFoundException если нет
    37→    // Если меняется кадастровый номер – проверить уникальность
    38→    if (data.cadastralNumber) {
    39→      const existing = await this.buildingRepository.findByCadastralNumber(data.cadastralNumber);
    40→      if (existing && existing.id !== id) {
    41→        throw new ConflictException('Здание с таким кадастровым номером уже существует');
    42→      }
    43→    }
    44→    const updated = await this.buildingRepository.update(id, data);
    45→    return this.toResponseDto(updated);
    46→  }
    47→
    48→  async delete(id: string): Promise<void> {
    49→    // Проверяем, существует ли
    50→    await this.findOne(id);
    51→    await this.buildingRepository.delete(id);
    52→  }
    53→
    54→  private toResponseDto(building: any): BuildingResponseDto {
    55→    return {
    56→      id: building.id,
    57→      address: building.address,
    58→      cadastralNumber: building.cadastralNumber,
    59→      yearBuilt: building.yearBuilt,
    60→      floors: building.floors,
    61→      entrances: building.entrances,
    62→      totalArea: building.totalArea,
    63→      totalPremises: building.totalPremises,
    64→      createdAt: building.createdAt,
    65→      updatedAt: building.updatedAt,
    66→    };
    67→  }
    68→}

